import React, { useRef, useMemo, useState, useEffect } from 'react';
import { Canvas, useFrame, useThree } from '@react-three/fiber';
import { Line } from '@react-three/drei';
import * as THREE from 'three';

// ─── CAMERA CONTROLLER (Scroll & Mouse Parallax) ───
const CameraController: React.FC = () => {
  const { camera } = useThree();
  const [scrollY, setScrollY] = useState(0);
  const mouse = useRef({ x: 0, y: 0 });

  useEffect(() => {
    const handleScroll = () => {
      setScrollY(window.scrollY);
    };

    const handleMouseMove = (e: MouseEvent) => {
      // Normalize to -1 to 1 range
      mouse.current.x = (e.clientX / window.innerWidth) * 2 - 1;
      mouse.current.y = -(e.clientY / window.innerHeight) * 2 + 1;
    };

    window.addEventListener('scroll', handleScroll, { passive: true });
    window.addEventListener('mousemove', handleMouseMove);
    return () => {
      window.removeEventListener('scroll', handleScroll);
      window.removeEventListener('mousemove', handleMouseMove);
    };
  }, []);

  useFrame(({ clock }) => {
    const time = clock.getElapsedTime();
    
    // Circular orbit radius decreases slightly as user scrolls (zoom in effect)
    const baseRadius = 5.2 - Math.min(2.5, scrollY * 0.0035);
    // Slow rotational baseline + mouse panning offset
    const angle = time * 0.045 + (mouse.current.x * 0.18);
    
    const targetX = Math.sin(angle) * baseRadius;
    const targetZ = Math.cos(angle) * baseRadius;
    // Panning height adjusts dynamically with scroll and mouse movement
    const targetY = 1.0 + Math.sin(time * 0.12) * 0.3 + (mouse.current.y * 0.3) - (scrollY * 0.0008);

    // Smoothly interpolate camera positioning
    camera.position.x += (targetX - camera.position.x) * 0.06;
    camera.position.y += (targetY - camera.position.y) * 0.06;
    camera.position.z += (targetZ - camera.position.z) * 0.06;

    // Point camera towards center of refinery complex
    camera.lookAt(0, 0.3, 0);
  });

  return null;
};

// ─── COMPONENT: EXHAUST STEAM PARTICLES ───
interface SteamProps {
  position: [number, number, number];
}

const ExhaustSteam: React.FC<SteamProps> = ({ position }) => {
  const pointsRef = useRef<THREE.Points>(null);
  const count = 30;

  const [positions, speeds, scales] = useMemo(() => {
    const pos = new Float32Array(count * 3);
    const sp = new Float32Array(count);
    const sc = new Float32Array(count);
    for (let i = 0; i < count; i++) {
      // Spawn at chimney top with small random horizontal deviation
      pos[i * 3] = position[0] + (Math.random() - 0.5) * 0.1;
      pos[i * 3 + 1] = position[1] + Math.random() * 1.5;
      pos[i * 3 + 2] = position[2] + (Math.random() - 0.5) * 0.1;

      sp[i] = 0.4 + Math.random() * 0.5; // rising velocity
      sc[i] = 0.02 + Math.random() * 0.05; // size
    }
    return [pos, sp, sc];
  }, [position]);

  useFrame((state, delta) => {
    if (pointsRef.current) {
      const posArr = pointsRef.current.geometry.attributes.position.array as Float32Array;
      const time = state.clock.getElapsedTime();

      for (let i = 0; i < count; i++) {
        // Rise up
        posArr[i * 3 + 1] += speeds[i] * delta;
        // Float side to side like smoke in breeze
        posArr[i * 3] += Math.sin(time * 2 + i) * 0.003;

        // Reset if float height goes beyond threshold
        if (posArr[i * 3 + 1] > position[1] + 1.8) {
          posArr[i * 3 + 1] = position[1];
          posArr[i * 3] = position[0] + (Math.random() - 0.5) * 0.08;
          posArr[i * 3 + 2] = position[2] + (Math.random() - 0.5) * 0.08;
        }
      }
      pointsRef.current.geometry.attributes.position.needsUpdate = true;
    }
  });

  return (
    <points ref={pointsRef}>
      <bufferGeometry>
        <bufferAttribute
          attach="attributes-position"
          args={[positions, 3]}
        />
      </bufferGeometry>
      <pointsMaterial
        size={0.12}
        color="#a1a1a1"
        transparent
        opacity={0.35}
        depthWrite={false}
      />
    </points>
  );
};

// ─── COMPONENT: ROTATING MACHINE GEARS ───
interface GearProps {
  position: [number, number, number];
  radius: number;
  teeth: number;
  rotationSpeed?: number;
  axis?: 'x' | 'y' | 'z';
}

const RotatingIndustrialGear: React.FC<GearProps> = ({ 
  position, radius, teeth, rotationSpeed = 0.4, axis = 'z' 
}) => {
  const groupRef = useRef<THREE.Group>(null);

  useFrame((state) => {
    if (groupRef.current) {
      const angle = state.clock.getElapsedTime() * rotationSpeed;
      if (axis === 'z') groupRef.current.rotation.z = angle;
      else if (axis === 'x') groupRef.current.rotation.x = angle;
      else groupRef.current.rotation.y = angle;
    }
  });

  // Calculate teeth segments
  const teethMeshes = useMemo(() => {
    const list = [];
    const toothWidth = (2 * Math.PI * radius) / (teeth * 2.2);
    for (let i = 0; i < teeth; i++) {
      const theta = (i / teeth) * Math.PI * 2;
      const x = Math.sin(theta) * radius;
      const y = Math.cos(theta) * radius;
      list.push(
        <mesh 
          key={i} 
          position={[x, y, 0]} 
          rotation={[0, 0, -theta]}
        >
          <boxGeometry args={[toothWidth, 0.15, 0.15]} />
          <meshStandardMaterial color="#1e293b" metalness={0.9} roughness={0.1} />
        </mesh>
      );
    }
    return list;
  }, [radius, teeth]);

  return (
    <group position={position}>
      <group ref={groupRef}>
        {/* Core center cylinder */}
        <mesh rotation={[Math.PI / 2, 0, 0]}>
          <cylinderGeometry args={[radius * 0.9, radius * 0.9, 0.12, 16]} />
          <meshStandardMaterial color="#1e293b" metalness={0.9} roughness={0.15} />
        </mesh>
        
        {/* Center hub */}
        <mesh rotation={[Math.PI / 2, 0, 0]}>
          <cylinderGeometry args={[radius * 0.25, radius * 0.25, 0.16, 8]} />
          <meshStandardMaterial color="#0066ff" metalness={0.95} roughness={0.05} />
        </mesh>
        
        {/* Teeth */}
        {teethMeshes}
      </group>
    </group>
  );
};

