// ─── COMPONENT: AMBIENT GLOW DUST PARTICLES ───
const GlowDust: React.FC = () => {
  const count = 70;
  const pointsRef = useRef<THREE.Points>(null);

  const [positions, speeds] = useMemo(() => {
    const pos = new Float32Array(count * 3);
    const sp = new Float32Array(count);
    for (let i = 0; i < count; i++) {
      pos[i * 3] = (Math.random() - 0.5) * 8; // X
      pos[i * 3 + 1] = -1.8 + Math.random() * 4; // Y
      pos[i * 3 + 2] = (Math.random() - 0.5) * 8; // Z
      sp[i] = 0.04 + Math.random() * 0.08;
    }
    return [pos, sp];
  }, []);

  useFrame((state, delta) => {
    if (pointsRef.current) {
      const pos = pointsRef.current.geometry.attributes.position.array as Float32Array;
      const time = state.clock.getElapsedTime();

      for (let i = 0; i < count; i++) {
        // Slow vertical drift
        pos[i * 3 + 1] += speeds[i] * delta;
        // Wavy drift
        pos[i * 3] += Math.sin(time * 0.5 + i) * 0.001;

        if (pos[i * 3 + 1] > 3.0) {
          pos[i * 3 + 1] = -1.8;
          pos[i * 3] = (Math.random() - 0.5) * 8;
        }
      }
      pointsRef.current.geometry.attributes.position.needsUpdate = true;
    }
  });

  return (
    <points ref={pointsRef}>
      <bufferGeometry>
        <bufferAttribute
          attach="attributes-position"
          args={[positions, 3]}
        />
      </bufferGeometry>
      <pointsMaterial
        size={0.04}
        color="#0066ff"
        transparent
        opacity={0.6}
        depthWrite={false}
      />
    </points>
  );
};

